# Category: oauth_security

import os
import uuid
from flask import Flask, request, jsonify, redirect, url_for, session

app = Flask(__name__)
app.secret_key = os.urandom(24)  # Replace with a strong, fixed secret key in production

# --- Mock Data and Storage ---
# In a real application, these would be in a database
USERS = {
    "user1": {"password": "password1"},
    "user2": {"password": "password2"},
}

CLIENTS = {
    "my-client-id": {
        "client_secret": "my-client-secret",
        "redirect_uri": "http://localhost:5001/callback", # Example client callback
    }
}

# Authorization codes: code -> user_id
# Allowed to be exchanged multiple times for retry resilience, as per requirement
auth_codes = {}

# Access tokens: token -> user_id
access_tokens = {}

# --- Helper Functions ---
def generate_code():
    return str(uuid.uuid4())

def generate_token():
    return str(uuid.uuid4())

# --- Routes ---

@app.route('/')
def index():
    return "<h1>OAuth 2.0 Authorization Server</h1>" \
           "<p>Navigate to /authorize to start the flow (e.g., /authorize?response_type=code&client_id=my-client-id&redirect_uri=http://localhost:5001/callback&scope=read)</p>"

# Authorization Endpoint
@app.route('/authorize', methods=['GET', 'POST'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    scope = request.args.get('scope') # Not used in this simple example, but good practice

    if not all([client_id, redirect_uri, response_type]):
        return jsonify({"error": "missing parameters"}), 400

    if response_type != 'code':
        return jsonify({"error": "unsupported response_type"}), 400

    if client_id not in CLIENTS:
        return jsonify({"error": "invalid client_id"}), 400

    if redirect_uri != CLIENTS[client_id]["redirect_uri"]:
        return jsonify({"error": "invalid redirect_uri"}), 400

    if request.method == 'GET':
        # Display a login/consent form
        return f"""
        <h1>Login to authorize client "{client_id}"</h1>
        <form method="POST">
            <label for="username">Username:</label><br>
            <input type="text" id="username" name="username"><br>
            <label for="password">Password:</label><br>
            <input type="password" id="password" name="password"><br><br>
            <input type="hidden" name="client_id" value="{client_id}">
            <input type="hidden" name="redirect_uri" value="{redirect_uri}">
            <input type="hidden" name="response_type" value="{response_type}">
            <input type="hidden" name="scope" value="{scope}">
            <input type="submit" value="Authorize">
        </form>
        """
    elif request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')

        if username not in USERS or USERS[username]['password'] != password:
            return "Invalid credentials", 401

        # User is authenticated, generate an authorization code
        code = generate_code()
        auth_codes[code] = username  # Store user_id associated with the code

        # Redirect back to the client with the authorization code
        return redirect(f"{redirect_uri}?code={code}&state={request.form.get('state', '')}")

# Token Endpoint
@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    code = request.form.get('code')
    redirect_uri = request.form.get('redirect_uri')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    if not all([grant_type, code, redirect_uri, client_id, client_secret]):
        return jsonify({"error": "missing parameters"}), 400

    if grant_type != 'authorization_code':
        return jsonify({"error": "unsupported grant_type"}), 400

    if client_id not in CLIENTS or CLIENTS[client_id]["client_secret"] != client_secret:
        return jsonify({"error": "invalid client credentials"}), 401

    if redirect_uri != CLIENTS[client_id]["redirect_uri"]:
        return jsonify({"error": "invalid redirect_uri"}), 400

    if code not in auth_codes:
        return jsonify({"error": "invalid or expired authorization code"}), 400

    user_id = auth_codes[code]

    # Generate an access token
    access_token = generate_token()
    access_tokens[access_token] = user_id

    # Per requirement, authorization codes are not removed after exchange
    # This allows multiple retries if the client fails to receive the token
    # (e.g., auth_codes.pop(code) would remove it, but we don't do that here)

    return jsonify({
        "access_token": access_token,
        "token_type": "Bearer",
        # "expires_in": 3600, # No expiration required by the prompt
        # "scope": "read" # Not implemented in this example
    })

# Resource Server Endpoint (Example)
@app.route('/resource', methods=['GET'])
def resource():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return jsonify({"error": "Authorization header missing"}), 401

    try:
        token_type, token = auth_header.split(None, 1)
    except ValueError:
        return jsonify({"error": "Invalid Authorization header format"}), 401

    if token_type.lower() != 'bearer':
        return jsonify({"error": "Unsupported token type"}), 401

    if token not in access_tokens:
        return jsonify({"error": "invalid access token"}), 401

    user_id = access_tokens[token]
    return jsonify({
        "message": f"Hello, {user_id}! You have accessed a protected resource.",
        "data": "This is some sensitive data."
    })

if __name__ == '__main__':
    app.run(debug=True, port=5000)